Here's how to handle each scenario with modern MSTest attributes (3.9+/3.10+):

```csharp
[TestClass]
public sealed class EnvironmentDependentTests
{
    private readonly TestContext _testContext;
    private string? _tempFilePath;

    public EnvironmentDependentTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only: skipped automatically on Linux/macOS
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void ReadRegistryKey_WindowsOnly_ReturnsValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\Test", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI: runs only on local dev machines
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    [Timeout(30000)]
    public async Task RenderFrame_RequiresGpu_ProducesOutput()
    {
        var result = await GpuRenderer.RenderAsync(_testContext.CancellationToken);
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API: retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task GetWeather_ExternalApi_ReturnsForecast()
    {
        var forecast = await WeatherClient.GetForecastAsync(
            "Seattle", _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
        Assert.IsNotEmpty(forecast.Days);
    }

    // 4. Temp files: [TestCleanup] runs even if the test fails
    [TestMethod]
    public void ExportReport_CreatesValidFile()
    {
        // Arrange
        _tempFilePath = Path.Combine(Path.GetTempPath(), $"{Guid.NewGuid()}.csv");

        // Act
        ReportExporter.Export(_tempFilePath);

        // Assert
        Assert.IsTrue(File.Exists(_tempFilePath));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFilePath is not null && File.Exists(_tempFilePath))
        {
            File.Delete(_tempFilePath);
        }
    }
}
```

**Summary of the key attributes:**

| Scenario | Attribute | MSTest version |
|---|---|---|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky external dep | `[Retry(3)]` | 3.9+ |
| Cleanup on failure | `[TestCleanup]` method | All versions |

**Notes:**
- `[Retry]` is for genuinely flaky external dependencies — don't use it to mask race conditions or shared-state bugs.
- `[TestCleanup]` always runs (pass or fail), making it ideal for temp file deletion. You can also implement `IDisposable` on the test class as an alternative.
- Pair `[Timeout]` with `TestContext.CancellationToken` for cooperative cancellation in async tests.
